import pandas as pd

ad = pd.DataFrame({
    'campaign': ['A', 'B', 'C', 'D', 'E'],
    'spend': [1000, 800, 600, 400, 1200],
    'revenue': [3500, 2200, 1500, 600, 2400]
})

ad['roas'] = (ad['revenue'] / ad['spend']).round(2)
ad['profit'] = ad['revenue'] - ad['spend']

# ROAS 기준 분류
def classify_roas(roas):
    if roas >= 4.0:
        return '우수 (ROAS>=4)'
    elif roas >= 2.0:
        return '양호 (2<=ROAS<4)'
    else:
        return '개선 필요 (ROAS<2)'

ad['grade'] = ad['roas'].apply(classify_roas)

print(ad[['campaign', 'spend', 'revenue', 'roas', 'profit', 'grade']]
      .sort_values('roas', ascending=False)
      .to_string(index=False))
